  ('locality-7ec62a85-moex-00244', 'locality-7ec62a85', 'locality-7ec62a85-moex-111-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '關於行政訴訟法上反訴，下列敘述何者錯誤？', '["僅行政訴訟之被告得提起反訴", "反訴須與本訴請求或其防禦方法相牽連", "反訴如專屬於本訴繫屬法院以外之行政法院管轄，應連同本訴一併移轉至該法院", "不得以提起反訴延滯訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "318", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00245', 'locality-7ec62a85', 'locality-7ec62a85-moex-111-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '下列何者，國家依法應負損害賠償責任？', '["設有「前有落石，禁止進入」警示之國家公園步道，人民仍冒險進入而遇難", "經公告之私人所有既成巷道上路燈突然倒塌致路人受傷", "進入已公告廢止使用之學校校舍夜宿，失足掉入坑洞受傷", "臺灣電力公司高壓電纜掉落致路人遭電死"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "318", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00246', 'locality-7ec62a85', 'locality-7ec62a85-moex-111-3082b5f1', 'sub-locality-7ec62a85-03', NULL, 'single_choice', '依實務見解，關於公法上返還請求權，下列敘述何者錯誤？', '["衛生福利部中央健康保險署向簽訂健保合約之醫療院所，請求返還溢領之醫療費用給付時，應 提起一般給付之訴", "人民之土地被徵收時，享有徵收補償之公法上請求權", "臺北市政府社會局撤銷違法授益性行政處分後，得以書面行政處分限期命受益人返還已受領之 給付", "行政主體間之給付關係，應依互相協商機制處理，不適用公法上返還請求權之規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "318", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00247', 'locality-7ec62a85', 'locality-7ec62a85-moex-110-8d1d3a67', 'sub-locality-7ec62a85-04', NULL, 'essay', '甲涉犯強盜罪嫌，檢察官以被害人（本質上屬證人）之身分傳喚乙到場，
乙即於偵查庭陳述被害經過，惟檢察官一時疏忽，未曾要乙具結。偵查
終結後，經檢察官向管轄法院提起公訴，法院於調查證據時，被告甲及
辯護人丙均知曉，檢察官所提出乙之偵訊筆錄，未經乙具結，仍未於辯
論終結前聲明異議。試論該陳述筆錄未經具結，是否得因被告及辯護人
均知曉卻未聲明異議而取得證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "d8cbf2e3ca13", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "316", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00248', 'locality-7ec62a85', 'locality-7ec62a85-moex-110-8d1d3a67', 'sub-locality-7ec62a85-04', NULL, 'essay', '甲涉犯毒品危害防制條例罪嫌，經檢察官聲請羈押，法官依法訊問後，
認為雖犯罪嫌疑重大且有羈押之原因，但無羈押之必要，依刑事訴訟法
第 101條之 2規定，逕命具保免予羈押。3個月後，甲經法院合法傳喚，
卻無正當理由不到庭，法院依刑事訴訟法第117條第 1 項規定，裁定「再
執行羈押」。試論法院裁定「再執行羈押」是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "d8cbf2e3ca13", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "316", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00249', 'locality-7ec62a85', 'locality-7ec62a85-moex-110-8d1d3a67', 'sub-locality-7ec62a85-04', NULL, 'essay', '乙男與孤兒之丙女離婚後，由丙獨自扶養兒子丁。丙於民國109年 12 月
14 日遭甲男無故毆打成傷，丙於110 年 3 月 22日前往偵查機關行告訴，
惟丙途中發生車禍死亡（丁當時年僅四歲）。嗣檢察官於 110年 10月 29
日偵查時，依刑事訴訟法第 236條規定，指定乙為丁之代行告訴人，乙
在同日當庭表示對甲為傷害罪之告訴。偵查終結後，檢察官向管轄法院
提起公訴，法院審理時，甲主張乙之代行告訴，已逾刑事訴訟法第 237
條規定 6 個月之期間，法院應依刑事訴訟法第 303 條第 3款為不受理判
決。試論甲之主張有無理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "d8cbf2e3ca13", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "316", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00250', 'locality-7ec62a85', 'locality-7ec62a85-moex-110-8d1d3a67', 'sub-locality-7ec62a85-04', NULL, 'essay', '甲涉犯貪污治罪條例罪嫌，經檢察官向管轄法院提起公訴，法院依法審
判後，諭知有罪，處有期徒刑 7年，甲不服依法提起上訴，上級審法院
由乙、丙、丁三位法官依法審理，仍諭知有罪，處有期徒刑 4年。甲不
服依法再向最高法院提起上訴，最高法院以上訴違背法律之程式，從程
序上駁回而告確定。甲再以有刑事訴訟法第 420條第 1項第 6款所定情
形，向原審法院聲請再審，原審法院由戊、丙、辛三位法官依法審理，
認為顯無理由，裁定予以駁回。甲不服，以原裁定與原判決之法官同
為丙，該法官未自行迴避為由，提起抗告。試論甲之抗告有無理由？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "d8cbf2e3ca13", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "316", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00251', 'locality-7ec62a85', 'locality-7ec62a85-moex-110-916530c6', 'sub-locality-7ec62a85-05', NULL, 'essay', '多年來，乙整日無所事事，不僅不願尋找工作機會，而且不時向同居人
甲伸手要錢作為賭資。乙因好賭欠下鉅額賭債。為此，甲與乙常有激烈
口角。某日，甲見到住家門口旁埋伏不少黑衣人手持球棒，準備毆打乙
討債。甲為了讓乙受點教訓，決定絕口不提門口有人準備暴力討債，同
時也不報警。大約一小時後，乙走出家門，即被埋伏的黑衣人毆打成傷。
事後證明，倘若甲當時有報警的話，警察當可即時趕到現場，避免乙遭
人持棒毆傷。試問甲之刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:10+00:00", "source_pdf_sha1": "cdc49ac2b7a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL)
